// 1. Sadə Funksiya Konstruktoru
function Pet(name, type) {
  this.name = name;
  this.type = type;
}

// Yeni ev heyvanları yaratma
const dog = new Pet("Rex", "Dog");
const cat = new Pet("Mimi", "Cat");

console.log(dog.name); // "Rex"
console.log(cat.type); // "Cat"

// 2. Metodların prototipə əlavə edilməsi
Pet.prototype.makeSound = function() {
  if (this.type === "Dog") {
    return `${this.name} hürməyə başladı!`;
  }
  return `${this.name} miyavlayır!`;
};

console.log(dog.makeSound()); // "Rex hürməyə başladı!"
console.log(cat.makeSound()); // "Mimi miyavlayır!"

// 3. Varsayılan dəyərlər
function SmartPet(name, type, energy = 100) {
  this.name = name;
  this.type = type;
  this.energy = energy;
}

SmartPet.prototype.play = function() {
  this.energy -= 10;
  return `${this.name} oynayır! Enerji: ${this.energy}`;
};

const smartDog = new SmartPet("Buddy", "Dog");
console.log(smartDog.play()); // "Buddy oynayır! Enerji: 90"

// 4. Dinamik xüsusiyyətlər
const customPet = new Pet("Fluffy", "Rabbit");
customPet.color = "white"; // Yeni xüsusiyyət əlavə etmək
console.log(customPet.color); // "white"

// Təhlükə nümunəsi: new açar sözü olmadan səhv
function FaultyPet(name) {
  this.name = name;
  this.energy = undefined; // Səhv: enerji təyin edilməyib
}

const faultyPet = FaultyPet("BadDog"); // Səhv: new istifadə edilməyib
console.log(window.name); // "BadDog" (this qlobal obyektə bağlıdır)

// Düzgün yanaşma
function SafePet(name, energy = 100) {
  if (!(this instanceof SafePet)) {
    return new SafePet(name, energy); // new olmadan çağırılıbsa, düzəliş
  }
  this.name = name;
  this.energy = energy;
}

SafePet.prototype.play = function() {
  this.energy -= 10;
  return `${this.name} oynayır! Enerji: ${this.energy}`;
};

const safePet = SafePet("GoodDog");
console.log(safePet.play()); // "GoodDog oynayır! Enerji: 90"

// Dinamik metod əlavə etmə
const customPet = new SafePet("Kitty", 120);
customPet.greet = function() {
  return `${this.name} salamlayır!`;
};
console.log(customPet.greet()); // "Kitty salamlayır!"

