// 1. Simple Function Constructor
function Pet(name, type) {
  this.name = name;
  this.type = type;
}

// Creating new pets
const dog = new Pet("Rex", "Dog");
const cat = new Pet("Mimi", "Cat");

console.log(dog.name); // "Rex"
console.log(cat.type); // "Cat"

// 2. Adding methods to the prototype
Pet.prototype.makeSound = function() {
  if (this.type === "Dog") {
    return `${this.name} is barking!`;
  }
  return `${this.name} is meowing!`;
};

console.log(dog.makeSound()); // "Rex is barking!"
console.log(cat.makeSound()); // "Mimi is meowing!"

// 3. Default values
function SmartPet(name, type, energy = 100) {
  this.name = name;
  this.type = type;
  this.energy = energy;
}

SmartPet.prototype.play = function() {
  this.energy -= 10;
  return `${this.name} is playing! Energy: ${this.energy}`;
};

const smartDog = new SmartPet("Buddy", "Dog");
console.log(smartDog.play()); // "Buddy is playing! Energy: 90"

// 4. Dynamic properties
const customPet = new Pet("Fluffy", "Rabbit");
customPet.color = "white"; // Adding a new property
console.log(customPet.color); // "white"

// Danger example: Error without new
function FaultyPet(name) {
  this.name = name;
  this.energy = undefined; // Error: energy not set
}

const faultyPet = FaultyPet("BadDog"); // Error: new not used
console.log(window.name); // "BadDog" (this binds to global object)

// Safe approach
function SafePet(name, energy = 100) {
  if (!(this instanceof SafePet)) {
    return new SafePet(name, energy); // Fix if new is forgotten
  }
  this.name = name;
  this.energy = energy;
}

SafePet.prototype.play = function() {
  this.energy -= 10;
  return `${this.name} is playing! Energy: ${this.energy}`;
};

const safePet = SafePet("GoodDog");
console.log(safePet.play()); // "GoodDog is playing! Energy: 90"

// Dynamic method addition
const customPet = new SafePet("Kitty", 120);
customPet.greet = function() {
  return `${this.name} greets you!`;
};
console.log(customPet.greet()); // "Kitty greets you!"

