// 1. Простой Конструктор функций
function Pet(name, type) {
  this.name = name;
  this.type = type;
}

// Создание новых питомцев
const dog = new Pet("Rex", "Dog");
const cat = new Pet("Mimi", "Cat");

console.log(dog.name); // "Rex"
console.log(cat.type); // "Cat"

// 2. Добавление методов в прототип
Pet.prototype.makeSound = function() {
  if (this.type === "Dog") {
    return `${this.name} лает!`;
  }
  return `${this.name} мяукает!`;
};

console.log(dog.makeSound()); // "Rex лает!"
console.log(cat.makeSound()); // "Mimi мяукает!"

// 3. Значения по умолчанию
function SmartPet(name, type, energy = 100) {
  this.name = name;
  this.type = type;
  this.energy = energy;
}

SmartPet.prototype.play = function() {
  this.energy -= 10;
  return `${this.name} играет! Энергия: ${this.energy}`;
};

const smartDog = new SmartPet("Buddy", "Dog");
console.log(smartDog.play()); // "Buddy играет! Энергия: 90"

// 4. Динамические свойства
const customPet = new Pet("Fluffy", "Rabbit");
customPet.color = "white"; // Добавление нового свойства
console.log(customPet.color); // "white"

// Пример опасности: Ошибка без new
function FaultyPet(name) {
  this.name = name;
  this.energy = undefined; // Ошибка: энергия не задана
}

const faultyPet = FaultyPet("BadDog"); // Ошибка: new не использован
console.log(window.name); // "BadDog" (this привязан к глобальному объекту)

// Безопасный подход
function SafePet(name, energy = 100) {
  if (!(this instanceof SafePet)) {
    return new SafePet(name, energy); // Исправление, если new забыли
  }
  this.name = name;
  this.energy = energy;
}

SafePet.prototype.play = function() {
  this.energy -= 10;
  return `${this.name} играет! Энергия: ${this.energy}`;
};

const safePet = SafePet("GoodDog");
console.log(safePet.play()); // "GoodDog играет! Энергия: 90"

// Динамическое добавление метода
const customPet = new SafePet("Kitty", 120);
customPet.greet = function() {
  return `${this.name} приветствует вас!`;
};
console.log(customPet.greet()); // "Kitty приветствует вас!"

